#!/usr/bin/env python3
"""
Omnisearch Configuration & Diagnostic Tool
Manages search plugins, sources, and provides feedback
"""

from flask import Flask, render_template_string, jsonify, request
import subprocess
import json
import os
from datetime import datetime

app = Flask(__name__)

PLUGINS = {
    "emacs-search": {
        "port": 8093,
        "endpoints": ["/buffers", "/search/buffers", "/search/kiro", "/search/files"],
        "description": "Search Emacs buffers and kiro sessions"
    },
    "plocate": {
        "command": "plocate --version",
        "description": "Fast file location database"
    },
    "ripgrep": {
        "command": "rg --version",
        "description": "Fast text search in files"
    },
    "knowledge": {
        "port": None,
        "description": "Knowledge base search (kiro-cli)"
    }
}

def check_service(port):
    """Check if service is running on port"""
    result = subprocess.run(
        f"ss -tlnp | grep :{port}",
        shell=True,
        capture_output=True,
        text=True
    )
    return result.returncode == 0

def check_command(cmd):
    """Check if command exists"""
    result = subprocess.run(
        cmd,
        shell=True,
        capture_output=True,
        text=True
    )
    return result.returncode == 0

def test_plugin(name, config):
    """Test plugin availability and functionality"""
    status = {
        "name": name,
        "available": False,
        "message": "",
        "details": {}
    }

    if "port" in config and config["port"]:
        port = config["port"]
        if check_service(port):
            status["available"] = True
            status["message"] = f"Service running on port {port}"

            # Test endpoints
            if "endpoints" in config:
                for endpoint in config["endpoints"]:
                    url = f"http://localhost:{port}{endpoint}"
                    result = subprocess.run(
                        f"curl -s -o /dev/null -w '%{{http_code}}' {url}",
                        shell=True,
                        capture_output=True,
                        text=True
                    )
                    status["details"][endpoint] = result.stdout.strip()
        else:
            status["message"] = f"Service not running on port {port}"

    elif "command" in config:
        if check_command(config["command"]):
            status["available"] = True
            result = subprocess.run(
                config["command"],
                shell=True,
                capture_output=True,
                text=True
            )
            status["message"] = result.stdout.strip().split('\n')[0]
        else:
            status["message"] = "Command not found"

    else:
        status["message"] = "Not configured"

    return status

def search_all(pattern):
    """Search across all available plugins"""
    results = {}

    for name, config in PLUGINS.items():
        if "port" in config and config["port"]:
            port = config["port"]
            if check_service(port):
                try:
                    result = subprocess.run(
                        f"curl -s -X POST http://localhost:{port}/search/buffers "
                        f"-H 'Content-Type: application/json' "
                        f"-d '{{\"pattern\":\"{pattern}\"}}'",
                        shell=True,
                        capture_output=True,
                        text=True,
                        timeout=5
                    )
                    data = json.loads(result.stdout)
                    results[name] = {
                        "count": len(data) if isinstance(data, list) else 0,
                        "results": data[:5] if isinstance(data, list) else []
                    }
                except Exception as e:
                    results[name] = {"error": str(e)}

        elif "command" in config and name == "plocate":
            try:
                result = subprocess.run(
                    f"plocate -l 5 '{pattern}' 2>/dev/null",
                    shell=True,
                    capture_output=True,
                    text=True,
                    timeout=5
                )
                files = result.stdout.strip().split('\n')
                results[name] = {
                    "count": len(files),
                    "results": files
                }
            except Exception as e:
                results[name] = {"error": str(e)}

        elif "command" in config and name == "ripgrep":
            try:
                result = subprocess.run(
                    f"rg -l --max-count 5 '{pattern}' ~/projects 2>/dev/null",
                    shell=True,
                    capture_output=True,
                    text=True,
                    timeout=5
                )
                files = result.stdout.strip().split('\n')
                results[name] = {
                    "count": len(files),
                    "results": files
                }
            except Exception as e:
                results[name] = {"error": str(e)}

    return results

DASHBOARD_HTML = """
<!DOCTYPE html>
<html>
<head>
    <title>Omnisearch Configuration</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { font-family: monospace; background: #1e1e1e; color: #d4d4d4; padding: 20px; }
        h1 { color: #4ec9b0; margin-bottom: 20px; }
        h2 { color: #569cd6; margin: 20px 0 10px 0; }
        .plugin { background: #252526; padding: 15px; margin: 10px 0; border-left: 3px solid #007acc; }
        .plugin.available { border-left-color: #4ec9b0; }
        .plugin.unavailable { border-left-color: #f48771; }
        .plugin-name { font-size: 18px; font-weight: bold; color: #4ec9b0; }
        .plugin-desc { color: #858585; margin: 5px 0; }
        .plugin-status { margin: 5px 0; }
        .status-ok { color: #4ec9b0; }
        .status-error { color: #f48771; }
        .details { margin: 10px 0; padding: 10px; background: #2d2d30; }
        .search-box { width: 100%; padding: 10px; background: #2d2d30; border: 1px solid #3e3e42; color: #d4d4d4; margin: 20px 0; }
        button { padding: 10px 20px; background: #007acc; border: none; color: white; cursor: pointer; margin: 5px; }
        button:hover { background: #005a9e; }
        .results { background: #252526; padding: 20px; margin: 20px 0; }
        .result-item { padding: 10px; margin: 5px 0; background: #2d2d30; }
        .result-source { color: #569cd6; font-weight: bold; }
        .result-count { color: #b5cea8; }
        .loading { color: #b5cea8; }
    </style>
</head>
<body>
    <h1>🔍 Omnisearch Configuration & Diagnostics</h1>

    <button onclick="diagnose()">🔧 Diagnose All Plugins</button>
    <button onclick="location.reload()">🔄 Refresh</button>

    <h2>Search Plugins</h2>
    <div id="plugins">Loading...</div>

    <h2>Test Search</h2>
    <input type="text" id="searchInput" class="search-box" placeholder="Enter search pattern..." onkeypress="if(event.key==='Enter')testSearch()">
    <button onclick="testSearch()">Search All Sources</button>

    <div id="searchResults"></div>

    <script>
        async function diagnose() {
            const pluginsDiv = document.getElementById('plugins');
            pluginsDiv.innerHTML = '<p class="loading">Diagnosing plugins...</p>';

            try {
                const response = await fetch('/api/diagnose');
                const plugins = await response.json();

                pluginsDiv.innerHTML = '';
                for (const [name, status] of Object.entries(plugins)) {
                    const div = document.createElement('div');
                    div.className = 'plugin ' + (status.available ? 'available' : 'unavailable');

                    let html = `
                        <div class="plugin-name">${name}</div>
                        <div class="plugin-desc">${status.description || ''}</div>
                        <div class="plugin-status ${status.available ? 'status-ok' : 'status-error'}">
                            ${status.available ? '✅' : '❌'} ${status.message}
                        </div>
                    `;

                    if (status.details && Object.keys(status.details).length > 0) {
                        html += '<div class="details">';
                        for (const [endpoint, code] of Object.entries(status.details)) {
                            html += `<div>${endpoint}: ${code}</div>`;
                        }
                        html += '</div>';
                    }

                    div.innerHTML = html;
                    pluginsDiv.appendChild(div);
                }
            } catch (error) {
                pluginsDiv.innerHTML = `<p class="status-error">Error: ${error.message}</p>`;
            }
        }

        async function testSearch() {
            const pattern = document.getElementById('searchInput').value;
            if (!pattern) return;

            const resultsDiv = document.getElementById('searchResults');
            resultsDiv.innerHTML = '<div class="results"><p class="loading">Searching...</p></div>';

            try {
                const response = await fetch('/api/search', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ pattern })
                });
                const results = await response.json();

                let html = '<div class="results">';
                html += `<h2>Search Results for "${pattern}"</h2>`;

                for (const [source, data] of Object.entries(results)) {
                    html += `<div class="result-item">`;
                    html += `<div class="result-source">${source}</div>`;

                    if (data.error) {
                        html += `<div class="status-error">Error: ${data.error}</div>`;
                    } else {
                        html += `<div class="result-count">Found: ${data.count} results</div>`;
                        if (data.results && data.results.length > 0) {
                            html += '<div class="details">';
                            data.results.forEach(r => {
                                if (Array.isArray(r)) {
                                    html += `<div>${r[0]}:${r[1]}: ${escapeHtml(r[2])}</div>`;
                                } else {
                                    html += `<div>${escapeHtml(r)}</div>`;
                                }
                            });
                            html += '</div>';
                        }
                    }
                    html += '</div>';
                }

                html += '</div>';
                resultsDiv.innerHTML = html;
            } catch (error) {
                resultsDiv.innerHTML = `<div class="results"><p class="status-error">Error: ${error.message}</p></div>`;
            }
        }

        function escapeHtml(text) {
            const div = document.createElement('div');
            div.textContent = text;
            return div.innerHTML;
        }

        // Auto-diagnose on load
        window.onload = diagnose;
    </script>
</body>
</html>
"""

@app.route('/')
def index():
    return render_template_string(DASHBOARD_HTML)

@app.route('/api/diagnose')
def api_diagnose():
    results = {}
    for name, config in PLUGINS.items():
        status = test_plugin(name, config)
        status["description"] = config["description"]
        results[name] = status
    return jsonify(results)

@app.route('/api/search', methods=['POST'])
def api_search():
    pattern = request.json.get('pattern', '')
    results = search_all(pattern)
    return jsonify(results)

@app.route('/api/plugins')
def api_plugins():
    return jsonify(PLUGINS)

if __name__ == "__main__":
    app.run(host='0.0.0.0', port=8094)

